class Solution:
    def beautifulPartitions(self, s, k, minLength):
        MOD = 10**9 + 7
        primes = set('2357')
        n = len(s)
        def is_prime(c):
            return c in primes
        from functools import lru_cache
        # brute: try every set of k-1 cut positions among 1..n-1
        import itertools
        if k > n:
            return 0
        count = 0
        positions = range(1, n)
        for cuts in itertools.combinations(positions, k - 1):
            bounds = [0] + list(cuts) + [n]
            ok = True
            for idx in range(k):
                a = bounds[idx]
                b = bounds[idx + 1]
                if b - a < minLength:
                    ok = False
                    break
                if not is_prime(s[a]) or is_prime(s[b - 1]):
                    ok = False
                    break
            if ok:
                count += 1
        return count % MOD

