class Solution:
    def beautifulPartitions(self, s, k, minLength):
        MOD = 10**9 + 7
        primes = set('2357')
        n = len(s)
        def can_start(i):
            return s[i] in primes
        def can_end(i):
            return s[i] not in primes
        if k * minLength > n or not can_start(0) or not can_end(n - 1):
            return 0
        # dp[j][i]: ways to partition first i chars into j pieces, with a cut before i
        dp = [[0] * (n + 1) for _ in range(k + 1)]
        dp[0][0] = 1
        for j in range(1, k + 1):
            pref = 0
            # i is the end position (exclusive) of the j-th piece
            # a piece ends at i-1, which must be a valid end, and starts at some p
            # where p is a valid start; cut positions are where a new piece can start
            for i in range(1, n + 1):
                # we can close a j-th piece ending at index i-1 if can_end(i-1)
                # add contributions of dp[j-1][p] for valid start p <= i-minLength
                p = i - minLength
                if p >= 0 and (p == 0 or can_start(p)):
                    pref = (pref + dp[j - 1][p]) % MOD
                if can_end(i - 1):
                    dp[j][i] = pref
                else:
                    dp[j][i] = 0
            # reset pref handled per j by recomputation above (pref accumulates within j)
        return dp[k][n] % MOD

