var beautifulPartitions = function(s, k, minLength) {
    const MOD = 1000000007n;
    const primes = new Set(['2', '3', '5', '7']);
    const n = s.length;
    const canStart = i => primes.has(s[i]);
    const canEnd = i => !primes.has(s[i]);
    if (k * minLength > n || !canStart(0) || !canEnd(n - 1)) return 0;
    const dp = Array.from({ length: k + 1 }, () => new Array(n + 1).fill(0n));
    dp[0][0] = 1n;
    for (let j = 1; j <= k; j++) {
        let pref = 0n;
        for (let i = 1; i <= n; i++) {
            const p = i - minLength;
            if (p >= 0 && (p === 0 || canStart(p))) {
                pref = (pref + dp[j - 1][p]) % MOD;
            }
            dp[j][i] = canEnd(i - 1) ? pref : 0n;
        }
    }
    return Number(dp[k][n] % MOD);
};
